# Module providing generic container and utilities
class Container:
    _items: list[float]

    def __init__(self):
        self._items = []

    def add(self, item: float):
        self._items.append(item)

    def get_all(self) -> list[float]:
        return self._items.copy()

    def count(self) -> int:
        return len(self._items)

def process_score(score: float) -> str:
    return f"Score: {score:.1f}"
